    72→    }
    73→
    74→    private PluginScanResult scanUrlsAndAddPlugins(PluginSource source) {
    75→        log.info("Loading plugin from: {}", source);
    76→        if (log.isDebugEnabled()) {
    77→            log.debug("Loading plugin urls: {}", Arrays.toString(source.urls()));
    78→        }
